// CORRECT: inline injection
@Injectable() class PrivacyGatekeeper { check(senderId, recipientId) { ... } }
// T73 constructor: @Inject(PrivacyGatekeeper) private readonly privacyGatekeeper: PrivacyGatekeeper
// Not: @EventPattern('privacy.check.requested') — async check introduces stale result risk

// CORRECT: atomic bidirectional write
await orm.transaction(() => [
  db.storeDocument('connections', { from: userA, to: userB, connectionId }),
  db.storeDocument('connections', { from: userB, to: userA, connectionId }),
]);
