// WRONG: if (score <= threshold) return; — drops items, causes silent empty-feed failures

// CORRECT: full recompute from graph
const listA = await db.getAdjacency(userA);
const listB = await db.getAdjacency(userB);
const mutualCount = listA.filter(id => listB.includes(id)).length;
await db.storeDocument('mutual-counts', { userA, userB, mutualCount });
